import os
import shutil
import tarfile
from zipfile import ZipFile
import subprocess

def backup_directory(source_dir, output_format='tar.gz'):
    if not os.path.exists(source_dir):
        raise ValueError(f"Source directory {source_dir} does not exist")

    base_name = os.path.basename(os.path.normpath(source_dir))
    temp_archive_name = f"{base_name}.temp.{output_format}"

    try:
        if output_format == 'tar.gz':
            with tarfile.open(temp_archive_name, "w:gz") as tar:
                tar.add(source_dir, arcname=base_name)
        elif output_format == 'tar.bz2':
            with tarfile.open(temp_archive_name, "w:bz2") as tar:
                tar.add(source_dir, arcname=base_name)
        elif output_format == 'zip':
            with ZipFile(temp_archive_name, 'w', zipfile.ZIP_DEFLATED) as zipf:
                for root, dirs, files in os.walk(source_dir):
                    for file in files:
                        file_path = os.path.join(root, file)
                        arcname = os.path.relpath(file_path, start=source_dir)
                        zipf.write(file_path, arcname)
        elif output_format == '7z':
            try:
                subprocess.run(['7z', 'a', temp_archive_name, source_dir], check=True)
            except FileNotFoundError:
                raise ValueError("7z command not found. Please install 7-Zip.")
        else:
            raise ValueError(f"Unsupported compression format: {output_format}")

    except Exception as e:
        os.remove(temp_archive_name) if os.path.exists(temp_archive_name) else None
        raise e

    return temp_archive_name

